INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-b20a8cf8-moex-00094', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '依警察職權行使法第8條第1項規定，警察對於已發生危害或依客觀合理判斷易生危害之交通工 具，得予以攔停並採行一定措施，請問下列何者不屬該項規定之措施？', '["要求駕駛人出示相關證件", "檢查引擎、車身號碼或其他足資識別之特徵", "搜索駕駛人身體", "要求駕駛人接受酒精濃度測試之檢定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00095', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '下列關於刑案犯罪現場的封鎖，何者錯誤？', '["實施犯罪調查，必要時得封鎖犯罪現場，並為即時之勘察", "實施前項封鎖時，應派員於封鎖線外警戒。非經在線外警戒警員同意，任何人不得進入", "經許可進入現場者，應著必要之防護裝備，避免破壞現場跡證", "現場封鎖得使用現場封鎖帶、標示牌、警示閃光燈或其他器材，以達成保全現場為原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00096', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '請問下列事務屬於犯罪現場調查組之任務者計有幾項？回實驗室利用科學儀器檢測搜索所得 證據。訪問被害人、報案人、發現人或其他關係人，瞭解案發時及案發前後，有無發現任何可 疑之人、事、物等，俾發掘可能之線索。對於現場附近之環境、交通狀況及案發當時之天候、 風向、氣溫、照明等進行必要之觀察並注意週期性出現之人、事、物查訪。如案情需要，得於 現場相關處所搜尋附近監視影像及其他可能遺留之各種跡證。', '["1項", "2項", "3項", "4項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00097', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '下列關於司法警察處理刑案時對被害人及家屬之保護之說明，何者錯誤？', '["秉持同理心及尊重態度，關懷協助被害人及家屬，適時提供相關資訊及服務", "被害人受傷案件，應先行訊問製作筆錄後再協助及護送就醫", "被害人死亡現場應立即實施封鎖，以帷幕及屍布將屍體遮蔽，並應儘速通報檢察官及早進行現 場勘驗及相驗工作", "為保護被害人家屬隱私，得依其要求，適當隔離媒體，減少不必要接觸，並提醒家屬偵查保密 的重要性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00098', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '司法警察實施偵查應進行案情研判，請問下列屬於案情判研應考量者計有幾項？犯罪之時間 犯罪之方法犯罪之動機犯罪被害人之範圍。', '["1項", "2項", "3項", "4項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00099', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '司法警察偵辦重大刑案發生除立即偵破外，均應訂定偵查計畫，以為偵查之準據，請問下列何者 不屬偵查計畫內容？', '["犯罪發生或發現之地點", "被害人之嗜好、接觸人物及被害狀況等生活情形", "司法警察偵辦期間所需人事費用", "現場訪問調查或資料查對情形"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00100', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '請問下列關於跟蹤或監視人員於執行時應注意事項之說明，何者正確？', '["為保護自身安全，應顯露隨身攜帶之武器、通訊器材及其他裝備", "外表舉止應融合當地環境。必要時，實施偽裝，隨時保持自然", "可穿戴引人注目之特殊物件", "不需備妥各種適當之交通工具、金融卡或電話卡等"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00101', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '司法警察偵查犯罪時，如須由被害人、檢舉人或目擊證人指認犯罪嫌疑人，應依警察機關實施指 認犯罪嫌疑人注意事項辦理，請問依該注意事項規定實施指認時，應依指認人描述之犯罪嫌疑人 特徵，安排幾名以上於外型無重大差異之被指認人，供指認人進行真人選擇式列隊指認？', '["3", "4", "5", "6"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00102', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警察機關逮捕何種犯罪之現行犯或通緝犯，應於製作筆錄時，詢問被告或犯罪嫌疑人有無監護或 照顧未滿12歲子女或兒童之情形，並調閱戶役政資料比對檢核，遇有兒童及少年福利與權益保障 法第53條第1項各款或第54條之情事者，應依各該條規定，通報直轄市、縣（市）主管機關？', '["違反毒品危害防制條例之犯罪", "竊盜罪", "詐欺罪", "偽造文書罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00103', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '司法警察偵查犯罪有刑事訴訟法第88條之1第1項所列情形之一，情況急迫，不及報告檢察官 者，得逕行拘提之，請問下列何者不屬於該條所規定之情形？', '["因現行犯之供述，且有事實足認為正犯或共犯嫌疑重大者", "在執行或在押中之脫逃者", "所犯顯係最重本刑為1年以下有期徒刑之罪，有事實足認為犯罪嫌疑重大，經被盤查而逃逸者", "所犯為最輕本刑為5年以上有期徒刑之罪，嫌疑重大，有事實足認為有逃亡之虞者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
